"use client";

import { useEffect, useRef } from "react";

// Pre-computed audio spectrum: 121 frames x 40 bars @ 20fps
const SPECTRUM_B64 =
  "";

const FPS = 20;
const FRAME_COUNT = 121;
const BAR_COUNT = 40;
const MAX_HEIGHT = 64;
const MIN_HEIGHT = 2;

let decodedFrames: Uint8Array[] | null = null;

function getFrames(): Uint8Array[] {
  if (decodedFrames) return decodedFrames;
  const binary = atob(SPECTRUM_B64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  decodedFrames = [];
  for (let f = 0; f < FRAME_COUNT; f++) {
    decodedFrames.push(bytes.slice(f * BAR_COUNT, (f + 1) * BAR_COUNT));
  }
  return decodedFrames;
}

export function AudioDemo() {
  const barsRef = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const frames = getFrames();
    const frameMs = 1000 / FPS;
    let raf: number;
    const start = performance.now();
    const current = new Float32Array(BAR_COUNT);

    function tick() {
      const elapsed = performance.now() - start;
      const exactFrame = (elapsed / frameMs) % FRAME_COUNT;
      const frameA = Math.floor(exactFrame);
      const frameB = (frameA + 1) % FRAME_COUNT;
      const t = exactFrame - frameA;

      const a = frames[frameA]!;
      const b = frames[frameB]!;

      for (let i = 0; i < BAR_COUNT; i++) {
        const el = barsRef.current[i];
        if (!el) continue;
        const target =
          MIN_HEIGHT + (a[i]! * (1 - t) + b[i]! * t) * ((MAX_HEIGHT - MIN_HEIGHT) / 255);
        // Exponential smoothing for extra fluidity
        current[i] += (target - current[i]) * 0.3;
        el.style.height = `${current[i]}px`;
      }

      raf = requestAnimationFrame(tick);
    }

    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, []);

  return (
    <div
      className="flex h-20 items-end gap-[1.5px]"
      style={{
        maskImage: "linear-gradient(to top, transparent 5%, black 20%)",
        WebkitMaskImage: "linear-gradient(to top, transparent 5%, black 20%)",
      }}
    >
      {Array.from({ length: BAR_COUNT }, (_, i) => (
        <div
          key={i}
          ref={(el) => {
            barsRef.current[i] = el;
          }}
          className="flex-1 rounded-t-full"
          style={{
            backgroundColor: "rgb(176,117,235)",
            height: MIN_HEIGHT,
            minHeight: MIN_HEIGHT,
          }}
        />
      ))}
    </div>
  );
}
